// Prepare date parameters for TikTok API
// Supports backfill mode via webhook body: { "backfill": true, "days": 90 }
// Default: last 7 days
// TikTok API uses start_date / end_date in YYYY-MM-DD format

const accounts = $input.all();

// Try to get webhook data
let webhookData = {};
try {
  const webhookNode = $('Webhook Trigger').first();
  if (webhookNode) {
    webhookData = webhookNode.json?.body || webhookNode.json || {};
  }
} catch(e) {
  // Webhook trigger may not have fired (schedule/manual)
}

const isBackfill = webhookData.backfill === true;
const backfillDays = Math.min(webhookData.days || 90, 180);

let startDate, endDate;
const now = new Date();
endDate = now.toISOString().split('T')[0];

if (isBackfill) {
  const since = new Date();
  since.setDate(since.getDate() - backfillDays);
  startDate = since.toISOString().split('T')[0];
} else {
  const since = new Date();
  since.setDate(since.getDate() - 7);
  startDate = since.toISOString().split('T')[0];
}

return accounts.map(item => ({
  json: {
    ...item.json,
    _startDate: startDate,
    _endDate: endDate,
    _isBackfill: isBackfill
  }
}));

// Parse TikTok ad names to extract template type and theme
// Same naming convention as Meta: {CLIENT}_{TEMPLATE}_{THEME}_{VERSION}

const TEMPLATE_CODES = {
  'MULTI': 'multi-item',
  'SPOT': 'spotlight',
  'SPOTLIGHT': 'spotlight',
  'EDU': 'educational',
  'CAROUSEL': 'carousel',
  'IMAGE': 'single-image',
  'BUY': 'acquisition',
  'AIA': 'aia',
  'BOOST': 'boost',
  'ORG': 'organic',
  'CUSTOM': 'custom'
};

function parseAdName(name) {
  let template_type = 'unknown';
  let theme = null;

  if (!name) return { template_type, theme };

  // NEW naming: {CLIENT}_{TEMPLATE}_{THEME}_{VERSION}
  const newFormatMatch = name.match(/^([A-Z]+)_([A-Z]+)_([^_]+)_(v\d+)$/i);
  if (newFormatMatch) {
    const [, client, templateCode, themePart, version] = newFormatMatch;
    const code = templateCode.toUpperCase();
    if (TEMPLATE_CODES[code]) {
      template_type = TEMPLATE_CODES[code];
      theme = themePart;
      return { template_type, theme };
    }
  }

  // Simpler: {CLIENT}_{TEMPLATE}_{THEME}
  const simpleMatch = name.match(/^([A-Z]+)_([A-Z]+)_(.+)$/i);
  if (simpleMatch) {
    const [, client, templateCode, themePart] = simpleMatch;
    const code = templateCode.toUpperCase();
    if (TEMPLATE_CODES[code]) {
      template_type = TEMPLATE_CODES[code];
      theme = themePart.replace(/_v\d+$/i, '');
      return { template_type, theme };
    }
  }

  return { template_type: 'unknown', theme: null };
}

const accountsData = $('Get Active TikTok Accounts').all();
const adsResponses = $input.all();
const results = [];

for (let i = 0; i < adsResponses.length; i++) {
  const account = accountsData[i]?.json;
  const response = adsResponses[i]?.json;

  if (!account) continue;

  // TikTok wraps ads in data.list
  const ads = response?.data?.list || [];

  if (ads.length === 0) {
    results.push({ json: { skip: true, reason: 'no ads for account ' + account.advertiser_id } });
    continue;
  }

  for (const ad of ads) {
    const { template_type, theme } = parseAdName(ad.ad_name);

    results.push({
      json: {
        tiktok_ad_id: String(ad.ad_id),
        tiktok_campaign_id: String(ad.campaign_id || ''),
        tiktok_adgroup_id: String(ad.adgroup_id || ''),
        advertiser_id: account.advertiser_id,
        name: ad.ad_name || '',
        status: ad.operation_status || ad.status || 'UNKNOWN',
        template_type: template_type,
        theme: theme,
        _accessToken: account.access_token,
        _startDate: account._startDate || accountsData[0]?.json?._startDate,
        _endDate: account._endDate || accountsData[0]?.json?._endDate,
        _isBackfill: account._isBackfill || false
      }
    });
  }
}

return results.length > 0 ? results : [{ json: { skip: true, reason: 'no ads found' } }];

// Group ads by account for insights fetch
const items = $input.all();
const accounts = $('Get Active TikTok Accounts').all();

// Get date params
const firstAccount = accounts[0]?.json || {};
const startDate = firstAccount._startDate;
const endDate = firstAccount._endDate;
const isBackfill = firstAccount._isBackfill || false;

// Build token lookup
const tokenMap = new Map();
for (const acc of accounts) {
  tokenMap.set(acc.json.advertiser_id, acc.json.access_token);
}

const accountMap = new Map();
for (const item of items) {
  const advertiserId = item.json.advertiser_id;
  if (!accountMap.has(advertiserId)) {
    accountMap.set(advertiserId, {
      advertiser_id: advertiserId,
      access_token: tokenMap.get(advertiserId),
      _startDate: startDate,
      _endDate: endDate,
      _isBackfill: isBackfill
    });
  }
}

return Array.from(accountMap.values()).map(a => ({ json: a }));

// Transform TikTok insights for database
// TikTok returns ALL metric values as strings — must parseFloat/parseInt

const accountsData = $('Group by Account').all();
const insightsResponses = $input.all();
const results = [];

for (let i = 0; i < insightsResponses.length; i++) {
  const account = accountsData[i]?.json;
  const response = insightsResponses[i]?.json;

  if (!account) continue;

  // TikTok wraps data in data.list
  const rows = response?.data?.list || [];

  for (const row of rows) {
    const dims = row.dimensions || {};
    const m = row.metrics || {};

    const spend = parseFloat(m.spend || '0');
    const conversions = parseInt(m.conversion || '0');
    const costPerConversion = parseFloat(m.cost_per_conversion || '0') || null;
    // Use conversions as leads equivalent for now
    const leads = conversions;
    const costPerLead = leads > 0 ? (spend / leads) : null;

    // TikTok stat_time_day is like "2026-02-15 00:00:00" — extract date
    const statDate = (dims.stat_time_day || '').split(' ')[0];

    results.push({
      json: {
        tiktok_ad_id: String(dims.ad_id),
        advertiser_id: account.advertiser_id,
        date_start: statDate,
        date_stop: statDate,
        spend: spend,
        impressions: parseInt(m.impressions || '0'),
        clicks: parseInt(m.clicks || '0'),
        ctr: parseFloat(m.ctr || '0'),
        cpc: parseFloat(m.cpc || '0'),
        cpm: parseFloat(m.cpm || '0'),
        video_play_actions: parseInt(m.video_play_actions || '0'),
        video_views_p25: parseInt(m.video_views_p25 || '0'),
        video_views_p50: parseInt(m.video_views_p50 || '0'),
        video_views_p75: parseInt(m.video_views_p75 || '0'),
        video_views_p100: parseInt(m.video_views_p100 || '0'),
        likes: parseInt(m.likes || '0'),
        comments: parseInt(m.comments || '0'),
        shares: parseInt(m.shares || '0'),
        follows: parseInt(m.follows || '0'),
        profile_visits: parseInt(m.profile_visits || '0'),
        conversions: conversions,
        cost_per_conversion: costPerConversion,
        leads: leads,
        cost_per_lead: costPerLead,
        actions_raw: JSON.stringify(m)
      }
    });
  }
}

return results.length > 0 ? results : [{ json: { skip: true, reason: 'no insights' } }];

